    "nextjs": "port React, { useState } from 'react';\nimport Link from 'next/link';\n\nexport default function SetupVar17Component() {\n  const [storeName, setStoreName] = useState('');\n  const [domain, setDomain] = useState('');\n\n  return (\n    <>\n{/* Note: @if and @for blocks from Angular need manual conversion to React syntax */}\n\n    <main className=\"min-h-screen flex items-center justify-center p-4 relative font-sans bg-zinc-950 text-zinc-200\">\n      \n      <Link href=\"/\" className=\"absolute top-6 left-6 flex items-center gap-2 text-sm font-bold tracking-widest uppercase opacity-70 hover:opacity-100 transition-opacity z-50 bg-black/50 px-4 py-2 rounded-full backdrop-blur-sm border border-zinc-800 text-zinc-300\"><span className=\"material-icons text-base\">arrow_back</span> Retornar</Link>\n      \n\n      <div className=\"max-w-7xl w-full grid grid-cols-1 lg:grid-cols-2 gap-0 lg:gap-16 items-center\">\n        \n        <!-- Left Side: Dark Mode Form -->\n        <div className=\"max-w-md mx-auto lg:mx-0 w-full p-8 lg:p-12 order-2 lg:order-1\">\n          <div className=\"mb-10\">\n            <div className=\"w-12 h-12 bg-violet-900/30 border border-violet-500/30 rounded-xl flex items-center justify-center mb-6 text-violet-400\">\n              <span className=\"material-icons text-2xl\">bolt</span>\n            </div>\n            <h1 className=\"text-3xl font-bold text-white tracking-tight mb-3\">Lançamento Rápido</h1>\n            <p className=\"text-zinc-400\">Sua plataforma de delivery pronta para operar em menos de 5 minutos.</p>\n          </div>\n\n          <form className=\"space-y-6\">\n            <div className=\"space-y-2\">\n              <label for=\"storeName17\" className=\"text-sm font-medium text-zinc-300\">Nome do Estabelecimento</label>\n              <input id=\"storeName17\" type=\"text\" value={storeName} onChange={(e) => setStoreName(e.target.value)} name=\"storeName\" placeholder=\"Ex: Cantina da Nonna\" className=\"w-full bg-zinc-900 border border-zinc-800 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-violet-500 focus:ring-1 focus:ring-violet-500 transition-all placeholder:text-zinc-600\" />\n            </div>\n\n            <div className=\"space-y-2\">\n              <label for=\"domain17\" className=\"text-sm font-medium text-zinc-300\">Endereço Web</label>\n              <div className=\"flex rounded-lg overflow-hidden border border-zinc-800 focus-within:border-violet-500 focus-within:ring-1 focus-within:ring-violet-500 transition-all\">\n                <input id=\"domain17\" type=\"text\" value={domain} onChange={(e) => setDomain(e.target.value)} name=\"domain\" placeholder=\"cantinadanonna\" className=\"w-full bg-zinc-900 px-4 py-3 text-white focus:outline-none placeholder:text-zinc-600\" />\n                <div className=\"bg-zinc-950 px-4 py-3 text-zinc-500 font-medium border-l border-zinc-800 flex items-center\">\n                  .delivery.app\n                </div>\n              </div>\n            </div>\n\n            <button type=\"button\" className=\"w-full mt-8 bg-violet-600 hover:bg-violet-500 text-white font-medium py-3.5 rounded-lg transition-colors shadow-lg shadow-violet-900/20 flex items-center justify-center gap-2\">\n              Iniciar Configuração <span className=\"material-icons text-sm\">arrow_forward</span>\n            </button>\n          </form>\n        </div>\n\n        <!-- Right Side: Dark Mode Illustration -->\n        <div className=\"relative h-[400px] lg:h-[700px] w-full bg-zinc-900 rounded-[2rem] border border-zinc-800 overflow-hidden order-1 lg:order-2 mb-8 lg:mb-0\">\n          <img src=\"https://images.unsplash.com/photo-1550547660-d9450f859349?q=80&w=1965&auto=format&fit=crop\" className=\"absolute inset-0 w-full h-full object-cover opacity-40 mix-blend-luminosity\" alt=\"Burger\" />\n          <div className=\"absolute inset-0 bg-gradient-to-t from-zinc-950 via-zinc-900/80 to-transparent\"></div>\n          \n          <div className=\"absolute bottom-12 left-12 right-12\">\n            <div className=\"bg-zinc-950/80 backdrop-blur-md border border-zinc-800 rounded-2xl p-6 shadow-2xl\">\n              <div className=\"flex items-center gap-4 mb-4\">\n                <div className=\"w-12 h-12 rounded-full bg-violet-900/50 border border-violet-500/30 flex items-center justify-center\">\n                  <span className=\"material-icons text-violet-400\">restaurant_menu</span>\n                </div>\n                <div>\n                  <h3 className=\"text-white font-bold\">Cardápio Digital</h3>\n                  <p className=\"text-sm text-zinc-400\">Atualize em tempo real</p>\n                </div>\n              </div>\n              <div className=\"h-2 w-full bg-zinc-800 rounded-full overflow-hidden\">\n                <div className=\"h-full bg-violet-500 w-3/4\"></div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </main>\n\n    \n  \n    </>\n  );\n}\n"
